fn solve(n: Int64, edges: Array<Array<Int64>>, source: Int64, target: Int64, k: Int64) -> Int64 {
    if source == target {
        return 0
    }

    // --- Graph setup and Candidate Thresholds ---

    let unique_weights: Set<Int64> = edges.iter().map { |e| e[2] }.collect();
    var candidates: Set<Int64> = Set.new();

    candidates.add(0); // Always test T=0

    for w in unique_weights {
        candidates.add(w);
        if w > 0 {
            candidates.add(w - 1);
        }
    }

    var sorted_candidates: Array<Int64> = candidates.to_a().sort();

    // Adjacency List: Adj[u] = Array<(v, w)>
    let mut adj: Array<Array<(Int64, Int64)>> = Array.new(n.to_int());
    for edge in edges {
        let u = edge[0];
        let v = edge[1];
        let w = edge[2];
        // Undirected graph
        adj[u.to_int()].push((v, w));
        adj[v.to_int()].push((u, w));
    }

    // --- Check Function ---
    // Checks if a path exists from source to target using <= k heavy edges, given threshold T.
    fn check(t: Int64) -> Bool {
