            Array.new(max_k + 1).fill(false) 
        };

        // Queue stores (node_id: Int64, heavy_count: Int)
        // We use a standard queue structure for BFS state exploration.
        let mut queue: Queue<(Int64, Int)> = Queue.new();

        if k < 0 { return false } // Should not happen based on constraints

        reachable[source.to_int()][0].set(true);
        queue.push((source, 0));

