/**
 * @param {number} n The number of nodes.
 * @param {number[][]} edges The list of weighted edges [u, v, w].
 * @param {number} source The starting node.
 * @param {number} target The destination node.
 * @param {number} k The maximum allowed heavy edges.
 * @return {number} The minimum threshold, or -1.
 */
function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // 1. Build Adjacency List
    const adj = Array(n).fill(0).map(() => []);
    let max_weight = 0;
    for (const [u, v, w] of edges) {
        adj[u].push({ node: v, weight: w });
        adj[v].push({ node: u, weight: w });
        if (w > max_weight) {
            max_weight = w;
        }
    }

    // Helper function to check reachability for a given threshold T using 0/1 BFS
    const canReach = (T) => {
        // D[i] stores the minimum number of heavy edges required to reach node i.
        // Since k is the upper bound, k + 1 serves as infinity relative to the constraint.
        const INF = k + 1;
        const D = Array(n).fill(INF);

        // Deque implementation using an array and pointers/indices
        const deque = [];

        D[source] = 0;
        deque.push(source); // Push front (conceptually)

        let head = 0;
        while (head < deque.length) {
            const u = deque[head++];
            const j = D[u]; // Current number of heavy edges

            if (u === target) {
                // Since 0/1 BFS finds the path with minimum cost first, 
                // if we reached target, D[target] <= k must hold implicitly 
                // due to pruning, but we check it explicitly here for safety.
                return j <= k;
            }

            for (const edge of adj[u]) {
                const v = edge.node;
                const w = edge.weight;

                // Cost: 1 if heavy (w > T), 0 if light (w <= T)
                const cost = (w > T) ? 1 : 0;
                const j_prime = j + cost;

                if (j_prime <= k && j_prime < D[v]) {
                    D[v] = j_prime;

                    if (cost === 0) {
                        // Light edge: push to front (conceptually, index 0)
                        // In array implementation, we insert at the beginning using unshift, 
                        // but since we are using index tracking (head), we can push and rely on the index management 
                        // combined with cost=0 paths being prioritized implicitly by the BFS nature 
                        // (though strict 0/1 BFS requires insertion at front).
                        // For simplicity and correctness in a simulation environment, we push to the front end of the queue array structure.
                        deque.unshift(v);
                    } else {
                        // Heavy edge: push to back
                        deque.push(v);
                    }
                }
            }
        }

        // If target was reached, it would have returned inside the loop.
        return D[target] <= k;
    };

    // 2. Binary Search for the minimum threshold T
    // Search range: [0, max_weight]. If max_weight is 0 (only possible if edges list was empty), this handles it.
    let L = 0;
    // We need to search up to max_weight + 1 conceptually, but since weights are <= 10^9, 
    // 10^9 covers all relevant thresholds. Let's use 10^9 + 1 as a safe upper bound R.
    let R = max_weight + 1; 

    // If no edges exist, max_weight = 0. We search [0, 1].
    if (edges.length === 0) {
         // If source != target and no edges, unreachable.
         return -1;
    }


    let min_T = -1;

    while (L <= R) {
        // Use Math.floor for integer division
        const M = L + Math.floor((R - L) / 2);

        if (canReach(M)) {
            // M works, store it, and try for a smaller threshold
            min_T = M;
            R = M - 1;
        } else {
            // M is too small, need a larger threshold
            L = M + 1;
        }
    }

    return min_T;
}
